@wsnyder continuation from #4226 .

Here is the sample code:

[t_unpacked_struct_comb_logic.tar.gz](https://github.com/verilator/verilator/files/11572345/t_unpacked_struct_comb_logic.tar.gz)

```systemverilog
module test (
        input wire clk,
        output logic  q
    );

    /* verilator lint_off UNOPTFLAT */
    typedef struct {
        logic overflow2;
        logic next;
    } comb_t;
    comb_t comb;
    /* verilator lint_on UNOPTFLAT */
 
    /* verilator lint_off ALWCOMBORDER */
    always_comb begin
        /* comb.next = 0; */
        if(comb.overflow2) begin 
            comb.next = 1;
        end else begin
            comb.next = 0;
        end
    end
    /* verilator lint_on ALWCOMBORDER */

    always_ff @(posedge clk) begin
        q <= comb.next;
    end
endmodule
```
